    if (daysSince > 7) {
      if (user.country === "US" || user.country === "GB") {
        if (daysSince > 30) {
          return "Pro";
        } else {
          return "Pro (trial)";
        }
      } else {
        if (daysSince > 14) {
          return "Pro";
        } else {
          return "";
        }
      }
    } else {
      return "";
    }
  } else if (user.plan === "pro") {
    if (daysSince > 90) {
      return "Team";
    }
    return "";
  } else if (user.plan === "team") {
    if (daysSince > 180) {
      return "Enterprise";
    }
    return "";
  } else {
    return "";
  }
}

